import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { API_PEOPLE, POSTER_PATH, WIDTH_300 } from '../constant';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import { FiChevronLeft, FiChevronRight } from 'react-icons/fi';
import axios from 'axios';
import frame1 from '../resources/Frame1.png'

const People = () => {
  const [data, setData] = useState([]);

  useEffect(() => {
    const getData = async () => {
      axios.get(API_PEOPLE)
        .then((data) => {
          setData(data.data.results);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, []);

  const ref = useRef(null);

  const scrollRight = (scrollOffset) => {
    ref.current.scrollLeft -= scrollOffset;
    if(!(ref.current.scrollLeft < (ref.current.scrollWidth-(ref.current.clientWidth*1.25)))) {
      ref.current.children[1].classList.remove('hide');
    }
    if(ref.current.scrollLeft <= 500) {
      ref.current.children[0].classList.add('hide');
    }
  };

  const scrollLeft = (scrollOffset) => {
    ref.current.scrollLeft += scrollOffset;
    if(!(ref.current.scrollLeft < (ref.current.scrollWidth-(ref.current.clientWidth*1.25)))) {
      ref.current.children[1].classList.add('hide');
    }
    if(ref.current.scrollLeft >= 0) {
      ref.current.children[0].classList.remove('hide');
    }
  };

  return (
    <div className="container">
      {data.length > 0 ?
        <div className="position-relative">
          <h2 className="mt-5">POPULAR PEOPLE</h2>
          <div className="cast-row" ref={ref}>
          <button className="btn btn-primary position-absolute scroll-button1 hide" onClick={() => scrollRight(500)}><FiChevronLeft /></button>
          <button className="btn btn-primary position-absolute scroll-button2" onClick={() => scrollLeft(500)}><FiChevronRight /></button>
            {data.map((dataRow, index) => (
              <Link key={index} className="card-link" to={'/movieshub/person/' + dataRow.id}>
                <div className="card frameWidth" key={index}>
                  <LazyLoadImage className="card-img-top" src={POSTER_PATH + WIDTH_300 + dataRow.profile_path} effect="opacity" alt={dataRow.name} onError={(e) => { e.target.onerror = null; e.target.src = frame1 }} />
                  <div className="card-body">
                    <div className="card-text">
                      <div>{dataRow.name}</div>
                      <div className="text-muted">{dataRow['known_for'].map((dataKnown, index) => (<span className="genre" key={index}>{dataKnown.title ? dataKnown.title : dataKnown.name}</span>))}</div>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div> : ''}
    </div>
  )
}

export default People
